using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45.00m, order.Total);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = CreateItems(("Book", 15.50m, 3));

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert
        Assert.AreEqual(46.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueId()
    {
        // Arrange
        var items = CreateItems(("Item", 5.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToUtcNow()
    {
        // Arrange
        var items = CreateItems(("Item", 5.00m, 1));
        var before = DateTime.UtcNow;

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsInRange(order.CreatedAt, before, after);
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems(("Item", 5.00m, 1));

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        // Arrange
        var items = CreateItems(("Item", 10.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        // Arrange
        var items = CreateItems(("Item", 10.00m, 1));
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items);

        // Act
        var orders = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        // Act
        var orders = _sut.GetOrdersByCustomer("unknown");

        // Assert
        Assert.IsEmpty(orders);
    }
}

